import socket as _socket
from concurrent.futures import ThreadPoolExecutor as _ThreadPoolExecutor


@st.cache_data(ttl=600, show_spinner=False)
def resolve_hostnames(ips: tuple[str, ...]) -> dict[str, str]:
    """Best-effort reverse DNS for a batch of IPs.

    Returns {ip: hostname_or_empty}. Uses a 2s per-IP timeout and resolves
    up to 10 IPs in parallel. Results are cached for 10 minutes so paging
    through the table is instant after the first resolve. Internal IPs
    without PTR records and external IPs without reverse DNS return ''.
    """
    def _resolve(ip: str) -> str:
        if not ip or ip in ("0.0.0.0", "", "?"):
            return ""
        try:
            with _ThreadPoolExecutor(max_workers=1) as ex:
                fut = ex.submit(_socket.gethostbyaddr, ip)
                return fut.result(timeout=2.0)[0]
        except Exception:
            return ""

    result: dict[str, str] = {}
    with _ThreadPoolExecutor(max_workers=10) as ex:
        futs = {ex.submit(_resolve, ip): ip for ip in ips}
        for fut in futs:
            ip = futs[fut]
            try:
                result[ip] = fut.result(timeout=3.0)
            except Exception:
                result[ip] = ""
    return result

